class Solution:
    def isAlienSorted(self, words, order):
        rank = {c: i for i, c in enumerate(order)}
        def le(a, b):
            for x, y in zip(a, b):
                if rank[x] != rank[y]:
                    return rank[x] < rank[y]
            return len(a) <= len(b)
        for i in range(len(words) - 1):
            if not le(words[i], words[i + 1]):
                return False
        return True

